const query = $('Webhook').first().json.query || {};

const orderId = query.order_id;
const version = parseInt(query.version || '1', 10);
const action = (query.action || '').toLowerCase();

if (!orderId) {
  return [{
    json: {
      action: 'error',
      html: '<html><body style="font-family:sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;"><div style="text-align:center;"><h1>❌ Error</h1><p>Missing order_id parameter.</p></div></body></html>'
    }
  }];
}

if (!['approve', 'retry', 'edit'].includes(action)) {
  return [{
    json: {
      action: 'error',
      html: '<html><body style="font-family:sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;"><div style="text-align:center;"><h1>❌ Error</h1><p>Invalid action.</p></div></body></html>'
    }
  }];
}

return [{
  json: {
    action,
    order_id: orderId,
    version
  }
}];

// APPROVE: Update script status + order status
const orderId = $('Review Router').first().json.order_id;
const version = $('Review Router').first().json.version;

return [{
  json: {
    order_id: orderId,
    version,
    html: `<!DOCTYPE html><html><head><meta charset="utf-8"><title>✅ Approved</title><style>body{font-family:'Segoe UI',sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh;background:#f0fdf4;margin:0;}.card{text-align:center;background:#fff;padding:48px;border-radius:16px;box-shadow:0 2px 8px rgba(0,0,0,0.06);}h1{font-size:24px;color:#16a34a;margin-bottom:8px;}p{color:#6b7280;font-size:14px;}</style></head><body><div class="card"><div style="font-size:48px;margin-bottom:16px;">✅</div><h1>Script Approved!</h1><p>Order: <strong>${orderId}</strong> · Version v${version}</p><p style="margin-top:16px;">The order is now ready for the next phase.</p></div></body></html>`
  }
}];

const orderId = $('Review Router').first().json.order_id;
const version = $('Review Router').first().json.version;

const env = $('Envs').first().json.env;
const WEBHOOK_URL = `https://evermagic.app.n8n.cloud/webhook${env.is_live ? '' : '-test'}/evermagic/review-submit`;


const html = `<!DOCTYPE html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>🔄 Retry — ${orderId}</title><style>*{box-sizing:border-box;margin:0;padding:0;}body{font-family:'Segoe UI',Roboto,sans-serif;background:#f8f9fa;padding:32px 16px;}.card{max-width:600px;margin:0 auto;background:#fff;border-radius:12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);overflow:hidden;}.header{padding:24px 32px;border-bottom:1px solid #eee;}.header h1{font-size:20px;color:#111;}.header p{font-size:13px;color:#6b7280;margin-top:4px;}.body{padding:24px 32px;}label{display:block;font-size:13px;font-weight:600;color:#374151;margin-bottom:6px;text-transform:uppercase;letter-spacing:0.5px;}textarea{width:100%;min-height:160px;padding:14px;border:1px solid #d1d5db;border-radius:8px;font-size:14px;line-height:1.6;resize:vertical;font-family:inherit;}textarea:focus{outline:none;border-color:#f59e0b;box-shadow:0 0 0 3px rgba(245,158,11,0.15);}.meta{font-size:12px;color:#9ca3af;margin-top:6px;}.actions{padding:16px 32px 28px;display:flex;gap:12px;}.btn{padding:12px 24px;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;text-decoration:none;text-align:center;}.btn-primary{background:#f59e0b;color:#fff;flex:1;}.btn-secondary{background:#e5e7eb;color:#374151;}.btn:hover{opacity:0.9;}</style></head><body><div class="card"><div class="header"><h1>🔄 Edit & Retry — AI Regeneration</h1><p>Order: <strong>${orderId}</strong> · Current version: v${version}</p></div><form action="${WEBHOOK_URL}" method="POST"><input type="hidden" name="order_id" value="${orderId}"><input type="hidden" name="version" value="${version}"><input type="hidden" name="action" value="retry_submit"><div class="body"><label for="feedback">Your feedback for the AI</label><textarea id="feedback" name="feedback" placeholder="Tell the AI what to change..." required></textarea><p class="meta">The AI will regenerate the script and you'll receive a new review email.</p></div><div class="actions"><button type="submit" class="btn btn-primary">🔄 Regenerate Script</button></div></form></div></body></html>`;

return [{ json: { html, order_id: orderId, version } }];

// n8n Code node — "Build Edit Form"
// Input comes from Supabase "Fetch Current Script" node
// which should return the script row with { order_id, version, content, ... }

const items = $input.all();
const scriptRow = items[0].json;

// Get order_id and version — try from the script row first, fall back to query
const orderId = scriptRow.order_id || $('Review Router')?.first()?.json?.order_id || 'unknown';
const version = scriptRow.version || $('Review Router')?.first()?.json?.version || 1;

// Get script content — handle both string and object
let script;
if (typeof scriptRow.content === 'string') {
  script = JSON.parse(scriptRow.content);
} else {
  script = scriptRow.content || {};
}

const scenes = Array.isArray(script.scenes) ? script.scenes : [];
const sceneCount = scenes.length;

const env = $('Envs').first().json.env;
const WEBHOOK_URL = `https://evermagic.app.n8n.cloud/webhook${env.is_live ? '' : '-test'}/evermagic/review-submit`;


// Escape HTML helper
function esc(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

// Build scene cards
const scenesHtml = scenes.map(s => {
  const num = s.scene_number;
  const emotions = ['wonder', 'excitement', 'tension', 'courage', 'triumph', 'joy', 'love'];
  const emotionOptions = emotions.map(e =>
    '<option value="' + e + '"' + (s.emotion === e ? ' selected' : '') + '>' + e + '</option>'
  ).join('');

  return '<div class="scene-card">' +
    '<div class="scene-header">' +
    '<span class="badge">Scene ' + num + '</span>' +
    '<select name="emotion_' + num + '" class="emo">' + emotionOptions + '</select>' +
    '</div>' +
    '<label>Scene Title</label>' +
    '<input type="text" name="scene_title_' + num + '" value="' + esc(s.scene_title) + '" class="inp">' +
    '<label>Narration <span class="hint">(read aloud)</span></label>' +
    '<textarea name="narration_' + num + '" rows="4" class="ta">' + esc(s.narration) + '</textarea>' +
    '<label>Visual Description <span class="hint">(for image gen)</span></label>' +
    '<textarea name="visual_' + num + '" rows="3" class="ta vis">' + esc(s.visual_description) + '</textarea>' +
    '</div>';
}).join('\n');

const html = '<!DOCTYPE html>' +
  '<html lang="en"><head><meta charset="utf-8">' +
  '<meta name="viewport" content="width=device-width,initial-scale=1.0">' +
  '<title>Edit Script - ' + esc(orderId) + '</title>' +
  '<style>' +
  '*{box-sizing:border-box;margin:0;padding:0}' +
  'body{font-family:Segoe UI,Roboto,sans-serif;background:#f8f9fa;padding:24px 16px;color:#111}' +
  '.card{max-width:720px;margin:0 auto;background:#fff;border-radius:12px;box-shadow:0 2px 12px rgba(0,0,0,.06);overflow:hidden}' +
  '.hdr{padding:24px 28px;border-bottom:1px solid #eee;display:flex;justify-content:space-between;align-items:flex-start}' +
  '.hdr h1{font-size:20px}.hdr p{font-size:13px;color:#6b7280;margin-top:4px}' +
  '.vbadge{padding:4px 12px;background:#e0e7ff;color:#3730a3;font-size:11px;font-weight:600;border-radius:12px}' +
  '.bd{padding:24px 28px}' +
  'label{display:block;font-size:12px;font-weight:600;color:#374151;margin:14px 0 4px;text-transform:uppercase;letter-spacing:.5px}' +
  'label .hint{font-weight:400;color:#9ca3af;text-transform:none;letter-spacing:0}' +
  '.inp{width:100%;padding:10px 12px;border:1px solid #d1d5db;border-radius:6px;font-size:15px;font-family:inherit;font-weight:600}' +
  '.inp:focus,.ta:focus,.tin:focus{outline:none;border-color:#3b82f6;box-shadow:0 0 0 3px rgba(59,130,246,.1)}' +
  '.ta{width:100%;padding:10px 12px;border:1px solid #d1d5db;border-radius:6px;font-size:14px;line-height:1.6;resize:vertical;font-family:inherit}' +
  '.ta.vis{font-size:13px;color:#6b7280;background:#f9fafb}' +
  '.scene-card{border:1px solid #e5e7eb;border-radius:10px;padding:20px;margin-bottom:16px}' +
  '.scene-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:4px}' +
  '.badge{font-size:12px;font-weight:700;color:#3730a3;text-transform:uppercase;letter-spacing:1px}' +
  '.emo{padding:4px 10px;border:1px solid #d1d5db;border-radius:6px;font-size:13px;background:#fff}' +
  '.top{background:#f9fafb;border:1px solid #e5e7eb;border-radius:10px;padding:20px;margin-bottom:20px}' +
  '.tin{width:100%;padding:10px 12px;border:1px solid #d1d5db;border-radius:6px;font-size:18px;font-weight:700;font-family:inherit}' +
  '.tag{width:100%;padding:10px 12px;border:1px solid #d1d5db;border-radius:6px;font-size:14px;font-style:italic;font-family:inherit;color:#6b7280}' +
  '.cls{width:100%;padding:10px 12px;border:1px solid #bbf7d0;border-radius:6px;font-size:14px;font-family:inherit;background:#f0fdf4}' +
  '.acts{padding:16px 28px 28px;display:flex;gap:12px;border-top:1px solid #eee}' +
  '.btn{padding:14px 28px;border:none;border-radius:8px;font-size:15px;font-weight:700;cursor:pointer;text-align:center;flex:1}' +
  '.btn-ok{background:#16a34a;color:#fff}.btn-no{background:#e5e7eb;color:#374151;flex:.4}' +
  '.btn:hover{opacity:.9}' +
  '</style></head><body>' +
  '<div class="card">' +
  '<div class="hdr"><div><h1>✏️ Edit Script</h1><p>Order: <strong>' + esc(orderId) + '</strong></p></div>' +
  '<span class="vbadge">v' + version + '</span></div>' +
  '<form id="ef" onsubmit="return go(event)">' +
  '<div class="bd">' +
  '<div class="top">' +
  '<label>Title</label>' +
  '<input type="text" id="title" value="' + esc(script.title) + '" class="tin" required>' +
  '<label>Tagline</label>' +
  '<input type="text" id="tagline" value="' + esc(script.tagline) + '" class="tag">' +
  '</div>' +
  scenesHtml +
  '<div class="top" style="background:#f0fdf4;border-color:#bbf7d0;margin-top:20px">' +
  '<label>💚 Closing Message</label>' +
  '<input type="text" id="closing" value="' + esc(script.closing_message) + '" class="cls">' +
  '</div>' +
  '</div>' +
  '<div class="acts">' +
  '<button type="submit" class="btn btn-ok">✅ Save &amp; Approve</button>' +
  '<button type="button" class="btn btn-no" onclick="window.close()">Cancel</button>' +
  '</div>' +
  '</form>' +
  '</div>' +
  '<script>' +
  'function go(e){' +
  'e.preventDefault();' +
  'var s={title:document.getElementById("title").value,' +
  'tagline:document.getElementById("tagline").value,' +
  'scenes:[],' +
  'closing_message:document.getElementById("closing").value};' +
  'for(var i=1;i<=' + sceneCount + ';i++){' +
  's.scenes.push({' +
  'scene_number:i,' +
  'scene_title:document.querySelector("[name=scene_title_"+i+"]").value,' +
  'narration:document.querySelector("[name=narration_"+i+"]").value,' +
  'visual_description:document.querySelector("[name=visual_"+i+"]").value,' +
  'emotion:document.querySelector("[name=emotion_"+i+"]").value' +
  '});' +
  '}' +
  'var f=document.createElement("form");' +
  'f.method="POST";f.action="' + WEBHOOK_URL + '";' +
  'var d={order_id:"' + orderId + '",version:"' + version + '",action:"edit_submit",script:JSON.stringify(s)};' +
  'for(var k in d){var inp=document.createElement("input");inp.type="hidden";inp.name=k;inp.value=d[k];f.appendChild(inp);}' +
  'document.body.appendChild(f);f.submit();' +
  '}' +
  '</script></body></html>';

return [{
  json: {
    html: html,
    order_id: orderId,
    version: version
  }
}];

const raw = {};
for (const item of $input.all()) {
  raw[item.json.key] = item.json.value;
}

const env = {
  mode: raw.mode,       
  is_live: raw.mode === 'live',
  script_approval_required: raw.script_approval_required === 'true',  
};

return [{ json: { env } }];
